#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    New,
    InProgress,
    Blocked,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Resolve,
    Reopen,
    Close,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::New;
    let mut was_resolved = false;

    for event in events {
        match event {
            Event::Start => {
                if matches!(status, Status::New | Status::Blocked) {
                    status = Status::InProgress;
                }
            }
            Event::Block => {
                if status == Status::InProgress {
                    status = Status::Blocked;
                }
            }
            Event::Unblock => {
                if status == Status::Blocked {
                    status = Status::InProgress;
                }
            }
            Event::Resolve => {
                if matches!(status, Status::InProgress | Status::Blocked) {
                    status = Status::Resolved;
                    was_resolved = true;
                }
            }
            Event::Reopen => {
                if was_resolved {
                    status = Status::InProgress;
                }
            }
            Event::Close => {
                if was_resolved {
                    status = Status::Closed;
                }
            }
        }
    }

    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event, Status};

    #[test]
    fn happy_path_can_close_after_resolution() {
        let events = [Event::Start, Event::Resolve, Event::Close];
        assert_eq!(apply_events(&events), Status::Closed);
    }

    #[test]
    fn cannot_close_without_current_resolution() {
        let events = [Event::Start, Event::Resolve, Event::Reopen, Event::Close];
        assert_eq!(apply_events(&events), Status::InProgress);
    }

    #[test]
    fn reopen_only_works_from_resolved_or_closed() {
        let events = [Event::Start, Event::Block, Event::Reopen];
        assert_eq!(apply_events(&events), Status::Blocked);
    }

    #[test]
    fn cannot_start_again_after_closure() {
        let events = [
            Event::Start,
            Event::Resolve,
            Event::Close,
            Event::Start,
            Event::Reopen,
            Event::Close,
        ];
        assert_eq!(apply_events(&events), Status::Closed);
    }

    #[test]
    fn blocked_work_can_be_resolved_and_then_reopened() {
        let events = [
            Event::Start,
            Event::Block,
            Event::Resolve,
            Event::Reopen,
            Event::Block,
            Event::Unblock,
        ];
        assert_eq!(apply_events(&events), Status::InProgress);
    }
}

