#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: String,
    pub wins: u32,
    pub losses: u32,
}

impl Player {
    fn games(&self) -> u32 {
        self.wins + self.losses
    }

    fn points(&self) -> i32 {
        self.wins as i32 * 3 - self.losses as i32
    }
}

pub fn rank_players(players: &[Player]) -> Vec<String> {
    let mut players = players.to_vec();
    players.sort_by(|a, b| {
        b.points()
            .cmp(&a.points())
            .then_with(|| a.games().cmp(&b.games()))
            .then_with(|| b.name.cmp(&a.name))
    });
    players.into_iter().map(|p| p.name).collect()
}

#[cfg(test)]
mod tests {
    use super::*;

    fn p(name: &str, wins: u32, losses: u32) -> Player {
        Player {
            name: name.to_string(),
            wins,
            losses,
        }
    }

    #[test]
    fn orders_by_points_descending() {
        let players = vec![p("Ava", 4, 0), p("Ben", 3, 1), p("Cara", 2, 0)];
        assert_eq!(rank_players(&players), vec!["Ava", "Ben", "Cara"]);
    }

    #[test]
    fn breaks_point_ties_by_fewer_games() {
        let players = vec![p("Mia", 3, 0), p("Noah", 4, 3), p("Omar", 2, 1)];
        assert_eq!(rank_players(&players), vec!["Mia", "Noah", "Omar"]);
    }

    #[test]
    fn breaks_full_ties_by_name_ascending() {
        let players = vec![p("Zoe", 2, 1), p("Amy", 2, 1), p("Liam", 1, 0)];
        assert_eq!(rank_players(&players), vec!["Amy", "Liam", "Zoe"]);
    }

    #[test]
    fn handles_empty_input() {
        let players: Vec<Player> = vec![];
        assert!(rank_players(&players).is_empty());
    }
}

use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub category: String,
    pub amount: i32,
}

pub fn summarize(entries: &[Entry]) -> Vec<String> {
    let mut totals: BTreeMap<String, i32> = BTreeMap::new();

    for entry in entries {
        *totals.entry(entry.category.clone()).or_insert(0) += entry.amount;
    }

    totals
        .into_iter()
        .map(|(category, total)| format!("{}:{}", category, total))
        .collect()
}

#[cfg(test)]
mod tests {
    use super::{summarize, Entry};

    fn e(category: &str, amount: i32) -> Entry {
        Entry {
            category: category.to_string(),
            amount,
        }
    }

    #[test]
    fn groups_positive_amounts_and_sorts_by_total_then_name() {
        let entries = vec![
            e("ops", 5),
            e("sales", 2),
            e("ops", 4),
            e("sales", 7),
            e("hr", 9),
        ];

        assert_eq!(summarize(&entries), vec!["ops:9", "hr:9", "sales:9"]);
    }

    #[test]
    fn skips_empty_categories_and_non_positive_amounts() {
        let entries = vec![
            e("", 8),
            e("ops", 0),
            e("ops", -3),
            e("sales", 4),
            e("sales", -1),
            e("hr", 1),
        ];

        assert_eq!(summarize(&entries), vec!["sales:4", "hr:1"]);
    }
}

