use std::cmp::Reverse;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: String,
    pub score: u32,
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut ordered = players.to_vec();
    ordered.sort_by_key(|p| (Reverse(p.score), Reverse(p.name.as_str())));
    ordered.into_iter().map(|p| p.name).collect()
}

#[cfg(test)]
mod tests {
    use super::*;

    fn p(name: &str, score: u32) -> Player {
        Player {
            name: name.to_string(),
            score,
        }
    }

    #[test]
    fn sorts_by_score_descending() {
        let players = vec![p("Mia", 15), p("Ava", 30), p("Zoe", 20)];
        assert_eq!(leaderboard(&players), vec!["Ava", "Zoe", "Mia"]);
    }

    #[test]
    fn ties_use_name_ascending() {
        let players = vec![p("Zoe", 10), p("Amy", 10), p("Bob", 10)];
        assert_eq!(leaderboard(&players), vec!["Amy", "Bob", "Zoe"]);
    }

    #[test]
    fn mixed_scores_and_ties() {
        let players = vec![
            p("Liam", 22),
            p("Noah", 18),
            p("Aiden", 22),
