}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub endpoint: String,
    pub timeout_ms: u64,
    pub retries: u8,
    pub verbose: bool,
}

impl Default for Config {
    fn default() -> Self {
        Self {
            endpoint: "https://default.service".to_string(),
            timeout_ms: 1000,
            retries: 2,
            verbose: false,
        }
    }
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub endpoint: Option<String>,
    pub timeout_ms: Option<u64>,
    pub retries: Option<u8>,
    pub verbose: Option<bool>,
}

pub fn merge_config(defaults: Config, env: PartialConfig, cli: PartialConfig) -> Config {
    let mut cfg = defaults;

    if let Some(endpoint) = cli.endpoint {
        if !endpoint.is_empty() {
            cfg.endpoint = endpoint;
        }
    } else if let Some(endpoint) = env.endpoint {
        if !endpoint.is_empty() {
            cfg.endpoint = endpoint;
        }
    }

    if let Some(timeout) = cli.timeout_ms {
        cfg.timeout_ms = timeout;
    } else if let Some(timeout) = env.timeout_ms {
        cfg.timeout_ms = timeout;
    }

    if let Some(retries) = cli.retries {
        cfg.retries = retries;
    } else if let Some(retries) = env.retries {
        cfg.retries = retries;
    }

    if let Some(verbose) = env.verbose {
        cfg.verbose = verbose;
    } else if let Some(verbose) = cli.verbose {
        cfg.verbose = verbose;
    }

    cfg
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn cli_values_override_env_and_defaults() {
        let defaults = Config::default();
        let env = PartialConfig {
            endpoint: Some("https://env.service".into()),
            timeout_ms: Some(2500),
            retries: Some(4),
            verbose: Some(false),
        };
        let cli = PartialConfig {
            endpoint: Some("https://cli.service".into()),
            timeout_ms: Some(5000),
            retries: Some(1),
            verbose: Some(true),
        };

        let merged = merge_config(defaults, env, cli);
        assert_eq!(merged.endpoint, "https://cli.service");
        assert_eq!(merged.timeout_ms, 5000);
        assert_eq!(merged.retries, 1);
        assert!(merged.verbose);
    }

    #[test]
    fn env_values_fill_when_cli_missing() {
        let defaults = Config::default();
        let env = PartialConfig {
            endpoint: Some("https://env.service".into()),
            timeout_ms: Some(2500),
            retries: Some(4),
            verbose: Some(true),
        };
        let cli = PartialConfig::default();

        let merged = merge_config(defaults, env, cli);
        assert_eq!(merged.endpoint, "https://env.service");
        assert_eq!(merged.timeout_ms, 2500);
        assert_eq!(merged.retries, 4);
        assert!(merged.verbose);
    }

    #[test]
    fn empty_cli_endpoint_does_not_erase_env_endpoint() {
        let defaults = Config::default();
        let env = PartialConfig {
            endpoint: Some("https://env.service".into()),
            timeout_ms: None,
            retries: None,
            verbose: None,
        };
        let cli = PartialConfig {
            endpoint: Some(String::new()),
            timeout_ms: None,
            retries: None,
            verbose: None,
        };

        let merged = merge_config(defaults, env, cli);
        assert_eq!(merged.endpoint, "https://env.service");
    }

    #[test]
    fn defaults_remain_when_no_overrides_present() {
        let merged = merge_config(Config::default(), PartialConfig::default(), PartialConfig::default());
        assert_eq!(merged, Config::default());
    }
}

