use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Order<'a> {
    pub day: &'a str,
    pub amount: u32,
    pub refunded: bool,
}

pub fn summarize_days(orders: &[Order<'_>]) -> Vec<String> {
    let mut totals: BTreeMap<&str, i64> = BTreeMap::new();

    for order in orders {
        if order.refunded {
            *totals.entry(order.day).or_insert(0) -= order.amount as i64;
        } else {
            *totals.entry(order.day).or_insert(0) += order.amount as i64;
        }
    }

    totals
        .into_iter()
        .map(|(day, total)| format!("{}={}", day, total))
        .collect()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn sorts_by_total_desc_then_day_and_skips_zero_total_days() {
        let orders = [
            Order { day: "wed", amount: 8, refunded: false },
            Order { day: "mon", amount: 10, refunded: false },
            Order { day: "tue", amount: 5, refunded: false },
            Order { day: "mon", amount: 3, refunded: true },
            Order { day: "tue", amount: 5, refunded: true },
            Order { day: "fri", amount: 7, refunded: false },
            Order { day: "wed", amount: 1, refunded: true },
        ];

        let report = summarize_days(&orders);
        assert_eq!(report, vec!["mon=7", "fri=7", "wed=7"]);
    }

    #[test]
