use std::collections::BTreeMap;

#[derive(Clone, Copy)]
struct Order {
    region: &'static str,
    shipped: u32,
    pending: u32,
    unit_price: u32,
}

#[derive(Default)]
struct Summary {
    orders: u32,
    shipped: u32,
    pending: u32,
    revenue: u32,
}

fn main() {
    let orders = [
        Order { region: "North", shipped: 3, pending: 0, unit_price: 10 },
        Order { region: "South", shipped: 0, pending: 4, unit_price: 5 },
        Order { region: "North", shipped: 2, pending: 0, unit_price: 10 },
        Order { region: "West", shipped: 1, pending: 2, unit_price: 8 },
        Order { region: "South", shipped: 1, pending: 0, unit_price: 10 },
        Order { region: "West", shipped: 1, pending: 0, unit_price: 12 },
    ];

    let mut by_region: BTreeMap<&str, Summary> = BTreeMap::new();
    let mut total = Summary::default();

    for order in orders {
        let entry = by_region.entry(order.region).or_default();
        entry.orders += 1;
        entry.shipped += order.shipped;
        entry.pending += order.pending;
        entry.revenue += (order.shipped + order.pending) * order.unit_price;

        total.orders += 1;
        total.shipped += order.shipped;
        total.pending += order.pending;
        total.revenue += order.shipped * order.unit_price;
    }

    for (region, summary) in by_region {
        println!(
            "{}: orders={} shipped={} pending={} revenue={}",
            region, summary.orders, summary.shipped, summary.pending, summary.revenue
        );
    }

    println!(
        "TOTAL: orders={} shipped={} pending={} revenue={}",
        total.orders, total.shipped, total.pending, total.revenue
    );
}

