#[derive(Clone, Copy)]
struct Booking {
    room: char,
    start: u32,
    end: u32,
}

#[derive(Clone, Copy)]
struct Request {
    room: char,
    user: &'static str,
    start: u32,
    end: u32,
}

fn overlaps(a: Booking, b: Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn can_book(existing: &[Booking], req: Request) -> bool {
    for booking in existing {
        if booking.room == req.room && overlaps(*booking, Booking { room: req.room, start: req.start, end: req.end }) {
            return false;
        }
    }
    true
}

fn main() {
    let requests = [
        Request { room: 'A', user: "alpha", start: 540, end: 600 },
        Request { room: 'A', user: "alpha", start: 600, end: 660 },
        Request { room: 'A', user: "alpha", start: 590, end: 610 },
        Request { room: 'A', user: "alpha", start: 700, end: 700 },
        Request { room: 'B', user: "beta", start: 590, end: 610 },
        Request { room: 'B', user: "beta", start: 610, end: 620 },
        Request { room: 'A', user: "beta", start: 590, end: 610 },
        Request { room: 'A', user: "alpha", start: 660, end: 720 },
        Request { room: 'A', user: "alpha", start: 720, end: 780 },
        Request { room: 'A', user: "alpha", start: 719, end: 721 },
    ];

    let mut accepted: Vec<Booking> = Vec::new();
    let mut out = Vec::new();

    for req in requests {
        if can_book(&accepted, req) {
            accepted.push(Booking { room: req.room, start: req.start, end: req.end });
            out.push(format!("accepted {} {} {} {}", req.room, req.user, req.start, req.end));
        } else {
            out.push(format!("rejected {} {} {} {}", req.room, req.user, req.start, req.end));
        }
    }

    println!("{}", out.join("\n"));
}

