use std::collections::BTreeMap;

#[derive(Clone, Debug)]
struct Ticket {
    status: &'static str,
    priority: u8,
}

enum Event {
    Open { id: &'static str, priority: u8 },
    Escalate { id: &'static str, by: u8 },
    Resolve { id: &'static str },
    Reopen { id: &'static str },
}

fn apply(events: &[Event]) -> BTreeMap<&'static str, Ticket> {
    let mut tickets = BTreeMap::new();
    for e in events {
        match *e {
            Event::Open { id, priority } => {
                tickets.insert(id, Ticket { status: "open", priority });
            }
            Event::Escalate { id, by } => {
                if let Some(t) = tickets.get_mut(id) {
                    t.priority = by;
                }
            }
            Event::Resolve { id } => {
                if let Some(t) = tickets.get_mut(id) {
                    t.status = "closed";
                    t.priority = 0;
                }
            }
            Event::Reopen { id } => {
                if let Some(t) = tickets.get_mut(id) {
                    t.status = "open";
                }
            }
        }
    }
    tickets
}

fn render(tickets: &BTreeMap<&'static str, Ticket>) -> String {
    let mut out = Vec::new();
    for (id, t) in tickets {
        out.push(format!("{}:{}:{}", id, t.status, t.priority));
    }
    out.join("\n")
}

