use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum State {
    Open,
    InProgress,
    Blocked,
    Closed,
}

#[derive(Clone, Copy)]
enum Event<'a> {
    Create(&'a str),
    Start(&'a str),
    Block(&'a str),
    Unblock(&'a str),
    Complete(&'a str),
    Reopen(&'a str),
}

fn apply(events: &[Event<'_>]) -> BTreeMap<String, (State, u32)> {
    let mut tasks: BTreeMap<String, (State, u32)> = BTreeMap::new();
    for event in events {
        match *event {
            Event::Create(id) => {
                tasks.insert(id.to_string(), (State::Open, 0));
            }
            Event::Start(id) => {
                if let Some((state, _)) = tasks.get_mut(id) {
                    *state = State::InProgress;
                }
            }
            Event::Block(id) => {
                if let Some((state, _)) = tasks.get_mut(id) {
                    *state = State::Blocked;
                }
            }
            Event::Unblock(id) => {
                if let Some((state, _)) = tasks.get_mut(id) {
                    *state = State::Open;
                }
            }
            Event::Complete(id) => {
                if let Some((state, completed)) = tasks.get_mut(id) {
                    *state = State::Closed;
                    *completed += 1;
                }
            }
            Event::Reopen(id) => {
                if let Some((state, _)) = tasks.get_mut(id) {
                    *state = State::Open;
                }
            }
        }
    }
    tasks
}

fn state_name(state: State) -> &'static str {
    match state {
        State::Open => "open",
        State::InProgress => "in_progress",
        State::Blocked => "blocked",
        State::Closed => "closed",
    }
}

fn main() {
    let events = [
        Event::Create("A"),
        Event::Start("A"),
        Event::Complete("A"),
        Event::Reopen("A"),
        Event::Block("A"),
        Event::Unblock("A"),
        Event::Complete("A"),
        Event::Create("B"),
        Event::Start("B"),
        Event::Block("B"),
        Event::Unblock("B"),
        Event::Block("B"),
        Event::Create("C"),
        Event::Start("C"),
        Event::Reopen("C"),
    ];

    let tasks = apply(&events);
    for (id, (state, completed)) in tasks {
        println!("{}:{}:{}", id, state_name(state), completed);
    }
}

