fn main() {
    let requests = [
        Booking { id: "A", start: 540, end: 600 },
        Booking { id: "B", start: 620, end: 660 },
        Booking { id: "C", start: 595, end: 615 },
        Booking { id: "D", start: 660, end: 690 },
        Booking { id: "E", start: 650, end: 670 },
        Booking { id: "F", start: 705, end: 720 },
        Booking { id: "G", start: 721, end: 730 },
    ];

    let mut accepted: Vec<Booking> = Vec::new();
    let mut rejected: Vec<String> = Vec::new();

    for req in requests {
        if !is_valid(&req) {
            rejected.push(format!("{} invalid", req.id));
            continue;
        }

        if let Some(existing) = accepted.iter().find(|b| overlaps(&req, b)) {
            rejected.push(format!("{} overlaps {}", req.id, existing.id));
        } else {
            accepted.push(req);
        }
    }

    println!("Accepted:");
    for b in &accepted {
        println!("{} {}-{}", b.id, b.start, b.end);
    }
    println!("Rejected:");
    for line in &rejected {
        println!("{}", line);
    }
