enum State {
    Open,
    InProgress,
    Closed,
}

enum Event {
    Start,
    Close,
    Reopen,
}

fn apply(mut state: State, events: &[Event]) -> State {
    for event in events {
        state = match (&state, event) {
            (State::Open, Event::Start) => State::InProgress,
            (State::InProgress, Event::Close) => State::Closed,
            (State::Closed, Event::Reopen) => State::InProgress,
            _ => state,
        };
    }
    state
}

fn label(state: State) -> &'static str {
    match state {
        State::Open => "Open",
        State::InProgress => "InProgress",
        State::Closed => "Closed",
    }
}

fn main() {
    let t1 = apply(State::Open, &[Event::Start, Event::Close]);
    let t2 = apply(State::Closed, &[Event::Reopen]);
    let t3 = apply(State::Open, &[Event::Close]);

