}

const INPUT: &str = "\nid=100|score=42|active=true\nid=101|score=abc|active=false\nid=|score=9|active=true\nid=102|active=true\nid=103|score=7|active=yes\nid=104|score=5|active=false|extra=oops\nid=105|score=0|active=false\n";

fn validate_line(line: &str) -> Result<(), &'static str> {
    let parts: Vec<&str> = line.split('|').collect();
    if parts.len() < 3 {
        return Err("wrong field count");
    }

    let mut id = None;
    let mut score = None;
    let mut active = None;

    for part in parts {
        let mut kv = part.splitn(2, '=');
        let key = kv.next().unwrap_or("");
        let value = kv.next().unwrap_or("");
        match key {
            "id" => id = Some(value),
            "score" => score = Some(value),
            "active" => active = Some(value),
            _ => {}
        }
    }

    match id {
        Some(v) if !v.is_empty() => {}
        _ => return Err("missing id"),
    }

    match score {
        Some(v) if v.parse::<u32>().is_ok() => {}
        Some(_) => return Err("bad score"),
        None => return Err("missing score"),
    }

    match active {
        Some("true") | Some("false") => {}
        _ => return Err("bad active"),
    }

    Ok(())
}

fn main() {
    let mut valid = 0;
    let mut invalids = Vec::new();

    for (idx, line) in INPUT.lines().enumerate() {
        match validate_line(line) {
            Ok(()) => valid += 1,
            Err(msg) => invalids.push(format!("{}:{}", idx, msg)),
        }
    }

    println!("valid:{} invalid:{}", valid, invalids.len());
    for item in invalids {
        println!("{}", item);
    }
}

