use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub region: &'static str,
    pub rep: &'static str,
    pub units: u32,
    pub returned: bool,
}

pub fn region_report(sales: &[Sale], min_units: u32) -> Vec<String> {
    let mut totals: BTreeMap<&str, (u32, usize)> = BTreeMap::new();

    for sale in sales {
        let entry = totals.entry(sale.region).or_insert((0, 0));
        entry.0 += sale.units;
        entry.1 += 1;
    }

    let mut rows: Vec<_> = totals
        .into_iter()
        .filter(|(_, (units, _))| *units >= min_units)
        .map(|(region, (units, count))| format!("{}:{} units/{} sales", region, units, count))
        .collect();

    rows.sort();
    rows
}

