#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Resolve,
    Close,
    Reopen,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Open, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Resolve) => Status::Resolved,
        (Status::Resolved, Event::Close) => Status::Closed,
        (Status::Resolved, Event::Reopen) => Status::Open,
        _ => status,
    }
}

pub fn apply_events(mut status: Status, events: &[Event]) -> Status {
    for &event in events {
        status = apply_event(status, event);
    }
    status
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn start_then_resolve_then_close() {
        let events = [Event::Start, Event::Resolve, Event::Close];
        assert_eq!(apply_events(Status::Open, &events), Status::Closed);
    }

    #[test]
    fn reopen_from_resolved_goes_back_to_open() {
        assert_eq!(apply_event(Status::Resolved, Event::Reopen), Status::Open);
    }

    #[test]
    fn close_from_open_is_ignored() {
        assert_eq!(apply_event(Status::Open, Event::Close), Status::Open);
    }

    #[test]
    fn reopen_from_closed_returns_to_open() {
        assert_eq!(apply_event(Status::Closed, Event::Reopen), Status::Open);
    }

    #[test]
    fn full_cycle_allows_closing_again_after_reopen() {
        let events = [
            Event::Start,
            Event::Resolve,
            Event::Close,
            Event::Reopen,
            Event::Start,
            Event::Resolve,
            Event::Close,
        ];
        assert_eq!(apply_events(Status::Open, &events), Status::Closed);
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub score: u32,
    pub wins: u32,
    pub penalty: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: usize,
    pub name: &'static str,
    pub score: u32,
    pub wins: u32,
    pub penalty: u32,
}

pub fn rank_players(players: &[Player]) -> Vec<RankedPlayer> {
    let mut sorted = players.to_vec();
    sorted.sort_by(|a, b| {
        b.score
            .cmp(&a.score)
            .then_with(|| a.penalty.cmp(&b.penalty))
            .then_with(|| a.name.cmp(&b.name))
    });

    let mut out = Vec::with_capacity(sorted.len());
    for (idx, p) in sorted.into_iter().enumerate() {
        let rank = if idx > 0 {
            let prev = &out[idx - 1];
            if prev.score == p.score && prev.penalty == p.penalty {
                prev.rank
            } else {
                idx + 1
            }
        } else {
            1
        };

        out.push(RankedPlayer {
            rank,
            name: p.name,
            score: p.score,
            wins: p.wins,
            penalty: p.penalty,
        });
    }
    out
}

