use std::collections::BTreeMap;

pub fn summarize(entries: &[(&str, i32)]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();

    for (category, amount) in entries {
        if *amount <= 0 {
            continue;
        }
        *totals.entry(category).or_insert(0) += *amount;
    }

    let mut out = String::new();
    let mut grand_total = 0;

    for (category, total) in totals {
        grand_total += total;
        out.push_str(&format!("{}:{}\n", category, total));
    }

    out.push_str(&format!("TOTAL:{}", grand_total));
    out
}

#[cfg(test)]
mod tests {
    use super::summarize;

    #[test]
    fn groups_counts_and_sorts_categories() {
        let report = summarize(&[
            ("ops", 5),
            ("sales", 3),
            ("ops", 2),
            ("admin", 4),
        ]);
        assert_eq!(report, "admin:4\nops:7\nsales:3\nTOTAL:14");
    }

    #[test]
    fn ignores_negative_rows_but_keeps_zero_totals_from_positive_and_negative_mix() {
        let report = summarize(&[
            ("ops", 5),
            ("ops", -5),
            ("sales", -3),
            ("admin", 0),
        ]);
        assert_eq!(report, "ops:0\nTOTAL:0");
    }

    #[test]
    fn omits_categories_that_only_have_zero_amount_entries() {
        let report = summarize(&[("ops", 0), ("admin", 0)]);
        assert_eq!(report, "TOTAL:0");
    }
}

