#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum TicketState {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Resolve,
    Close,
    Reopen,
}

pub fn apply_event(state: TicketState, event: Event) -> TicketState {
    match (state, event) {
        (TicketState::Open, Event::Start) => TicketState::InProgress,
        (TicketState::InProgress, Event::Resolve) => TicketState::Resolved,
        (TicketState::Resolved, Event::Close) => TicketState::Closed,
        (TicketState::Resolved, Event::Reopen) => TicketState::Open,
        (TicketState::Closed, Event::Reopen) => TicketState::Resolved,
        _ => state,
    }
}

pub fn apply_events(mut state: TicketState, events: &[Event]) -> TicketState {
    for &event in events {
        state = apply_event(state, event);
    }
    state
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn closed_ticket_reopens_to_open() {
        assert_eq!(apply_event(TicketState::Closed, Event::Reopen), TicketState::Open);
    }

    #[test]
    fn closed_ticket_can_restart_and_resolve_again() {
        let events = [Event::Reopen, Event::Start, Event::Resolve];
        assert_eq!(apply_events(TicketState::Closed, &events), TicketState::Resolved);
    }

    #[test]
    fn resolved_ticket_closes() {
        assert_eq!(apply_event(TicketState::Resolved, Event::Close), TicketState::Closed);
    }

    #[test]
    fn open_ticket_close_is_ignored() {
        assert_eq!(apply_event(TicketState::Open, Event::Close), TicketState::Open);
    }

    #[test]
    fn reopen_after_close_then_close_again_ends_closed() {
        let events = [Event::Reopen, Event::Close];
        assert_eq!(apply_events(TicketState::Closed, &events), TicketState::Closed);
    }
}

pub fn collect_tags(input: &[&str]) -> Vec<String> {
    input
        .iter()
        .filter_map(|raw| {
            let trimmed = raw.trim();
            if trimmed.starts_with('#') {
                Some(trimmed.to_lowercase())
            } else {
                None
            }
        })
        .fold(Vec::new(), |mut acc, tag| {
            if !acc.contains(&tag) {
                acc.push(tag);
            }
            acc
        })
}

#[cfg(test)]
mod tests {
