    #[test]
    fn keeps_hash_tags_lowercased_and_unique() {
        let input = [" #Rust ", "note", "#rust", "#CLI", "#cli", "#tools"];
        let got = collect_tags(&input);
        assert_eq!(got, vec!["#rust", "#cli", "#tools"]);
    }

    #[test]
    fn drops_bare_hash_and_whitespace_only_entries() {
        let input = ["#", "   ", "#One", " #  ", "#two "];
        let got = collect_tags(&input);
        assert_eq!(got, vec!["#one", "#two"]);
    }

    #[test]
    fn preserves_first_seen_order_after_filtering() {
        let input = ["misc", "#Beta", "#alpha", "#beta", "#ALPHA", "#gamma"];
        let got = collect_tags(&input);
        assert_eq!(got, vec!["#beta", "#alpha", "#gamma"]);
    }
}

