    use super::*;

    #[test]
    fn sorts_by_score_then_solved_then_penalty_then_name() {
        let rows = vec![
            Entry { name: "zoe", score: 90, solved: 3, penalty: 20 },
            Entry { name: "amy", score: 100, solved: 3, penalty: 50 },
            Entry { name: "bob", score: 100, solved: 4, penalty: 80 },
            Entry { name: "eve", score: 100, solved: 4, penalty: 30 },
            Entry { name: "dan", score: 100, solved: 4, penalty: 30 },
        ];

        let got = leaderboard(&rows);
        let names: Vec<&str> = got
            .iter()
            .map(|line| line.split_once(". ").unwrap().1.split(' ').next().unwrap())
            .collect();

        assert_eq!(names, vec!["dan", "eve", "bob", "amy", "zoe"]);
    }

    #[test]
    fn competition_ranks_ignore_name_only_ties() {
        let rows = vec![
            Entry { name: "beta", score: 80, solved: 2, penalty: 10 },
            Entry { name: "alpha", score: 80, solved: 2, penalty: 10 },
            Entry { name: "gamma", score: 70, solved: 5, penalty: 1 },
            Entry { name: "delta", score: 60, solved: 5, penalty: 1 },
        ];

        let got = leaderboard(&rows);
        let ranks: Vec<&str> = got
            .iter()
            .map(|line| line.split_once('.').unwrap().0)
            .collect();

        assert_eq!(ranks, vec!["1", "1", "3", "4"]);
    }

