#[derive(Debug, PartialEq, Eq)]
pub struct Record {
    pub id: u32,
    pub name: String,
    pub active: bool,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (line_no, raw) in input.lines().enumerate() {
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }

        let mut id = None;
        let mut name = None;
        let mut active = None;

        for part in line.split(';') {
            let (key, value) = part
                .split_once(':')
                .ok_or_else(|| format!("line {} malformed field", line_no + 1))?;
            match key.trim() {
                "id" => {
                    id = Some(value.trim().parse::<u32>().map_err(|_| {
                        format!("line {} invalid id", line_no + 1)
                    })?);
                }
                "name" => {
                    let v = value.trim();
                    if v.is_empty() {
                        return Err(format!("line {} empty name", line_no + 1));
                    }
                    name = Some(v.to_string());
                }
                "active" => {
                    active = Some(match value.trim() {
                        "true" => true,
                        "false" => false,
                        _ => return Err(format!("line {} invalid active", line_no + 1)),
                    });
                }
                _ => {}
            }
        }

        out.push(Record {
            id: id.ok_or_else(|| format!("line {} missing id", line_no + 1))?,
            name: name.ok_or_else(|| format!("line {} missing name", line_no + 1))?,
            active: active.unwrap_or(false),
        });
    }
    Ok(out)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parses_valid_records_with_optional_spacing() {
        let input = " id:1 ; name:Alice ; active:true\nname:Bob;active:false;id:2 ";
        let got = parse_records(input).unwrap();
        assert_eq!(
            got,
            vec![
                Record {
                    id: 1,
                    name: "Alice".into(),
                    active: true,
                },
                Record {
                    id: 2,
                    name: "Bob".into(),
                    active: false,
                }
            ]
        );
    }

    #[test]
    fn rejects_duplicate_keys_in_a_record() {
        let err = parse_records("id:1;name:A;active:true;name:B").unwrap_err();
        assert_eq!(err, "line 1 duplicate name");
    }

    #[test]
    fn active_is_required() {
        let err = parse_records("id:4;name:Delta").unwrap_err();
        assert_eq!(err, "line 1 missing active");
    }

    #[test]
    fn rejects_zero_id() {
        let err = parse_records("id:0;name:Zero;active:true").unwrap_err();
        assert_eq!(err, "line 1 invalid id");
    }
}

