use std::cmp::Ordering;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub name: String,
    pub score: u32,
    pub penalties: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedEntry {
    pub rank: usize,
    pub name: String,
    pub score: u32,
    pub penalties: u32,
}

pub fn rank_entries(entries: &[Entry]) -> Vec<RankedEntry> {
    let mut items = entries.to_vec();
    items.sort_by(|a, b| {
        b.score
            .cmp(&a.score)
            .then_with(|| b.penalties.cmp(&a.penalties))
            .then_with(|| b.name.cmp(&a.name))
    });

    items
        .into_iter()
        .enumerate()
        .map(|(idx, e)| RankedEntry {
            rank: idx + 1,
            name: e.name,
            score: e.score,
            penalties: e.penalties,
        })
        .collect()
}

#[cfg(test)]
mod tests {
    use super::*;

    fn e(name: &str, score: u32, penalties: u32) -> Entry {
        Entry {
            name: name.to_string(),
            score,
            penalties,
        }
    }

    #[test]
    fn orders_by_score_then_fewer_penalties_then_name() {
        let ranked = rank_entries(&[
            e("zoe", 15, 1),
            e("amy", 15, 0),
            e("bob", 15, 0),
            e("mia", 14, 0),
        ]);

        let names: Vec<_> = ranked.iter().map(|r| r.name.as_str()).collect();
        assert_eq!(names, vec!["amy", "bob", "zoe", "mia"]);
        let ranks: Vec<_> = ranked.iter().map(|r| r.rank).collect();
        assert_eq!(ranks, vec![1, 2, 3, 4]);
    }

    #[test]
    fn ties_share_rank_and_next_rank_skips() {
        let ranked = rank_entries(&[
            e("bob", 20, 1),
            e("amy", 20, 1),
            e("cy", 19, 0),
            e("dan", 18, 0),
        ]);

        let pairs: Vec<_> = ranked.into_iter().map(|r| (r.name, r.rank)).collect();
        assert_eq!(pairs, vec![
            ("amy".to_string(), 1),
            ("bob".to_string(), 1),
            ("cy".to_string(), 3),
            ("dan".to_string(), 4),
        ]);
    }

    #[test]
    fn exact_duplicates_keep_same_rank_across_larger_tie_block() {
        let ranked = rank_entries(&[
            e("ivy", 10, 2),
            e("abe", 10, 2),
            e("max", 10, 2),
            e("kim", 9, 0),
            e("ned", 9, 1),
        ]);

        let triples: Vec<_> = ranked
            .into_iter()
            .map(|r| (r.name, r.penalties, r.rank))
            .collect();
        assert_eq!(triples, vec![
            ("abe".to_string(), 2, 1),
            ("ivy".to_string(), 2, 1),
            ("max".to_string(), 2, 1),
            ("kim".to_string(), 0, 4),
            ("ned".to_string(), 1, 5),
        ]);
    }
}

