#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Resolve,
    Reopen,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::Open;

    for event in events {
        status = match (*event, status) {
            (Event::Start, Status::Open) => Status::InProgress,
            (Event::Resolve, Status::InProgress) => Status::Closed,
            (Event::Reopen, Status::Closed) => Status::Open,
            _ => status,
        };
    }

    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event, Status};

    #[test]
    fn resolves_after_start() {
        assert_eq!(apply_events(&[Event::Start, Event::Resolve]), Status::Closed);
    }

    #[test]
    fn reopen_moves_closed_back_to_in_progress() {
        assert_eq!(
            apply_events(&[Event::Start, Event::Resolve, Event::Reopen]),
            Status::InProgress
        );
    }

    #[test]
    fn can_resolve_again_after_reopen() {
        assert_eq!(
            apply_events(&[Event::Start, Event::Resolve, Event::Reopen, Event::Resolve]),
            Status::Closed
        );
    }
}

pub fn collect_visible_scores(rows: &[(&str, i32)]) -> Vec<String> {
    rows.iter()
        .filter_map(|(name, score)| {
            if *score > 0 {
                Some(format!("{}:{}", name, score))
            } else {
                None
            }
        })
        .collect()
}

