    }

    #[test]
    fn trims_names_and_caps_large_scores() {
        let rows = [("  dana  ", 105), ("eve", 100), (" frank", 101)];
        assert_eq!(
            collect_visible_scores(&rows),
            vec!["dana:100", "eve:100", "frank:100"]
        );
    }
