pub fn can_book(existing: &[(u32, u32)], start: u32, end: u32) -> bool {
    if start >= end {
        return false;
    }

    for &(s, e) in existing {
        if start <= e && end >= s {
            return false;
        }
    }

    true
}

#[cfg(test)]
mod tests {
    use super::can_book;

    #[test]
    fn rejects_overlap_inside_existing() {
        let existing = vec![(10, 20)];
        assert!(!can_book(&existing, 12, 18));
    }

    #[test]
    fn allows_back_to_back_after() {
        let existing = vec![(10, 20)];
        assert!(can_book(&existing, 20, 25));
    }

    #[test]
    fn allows_back_to_back_before() {
        let existing = vec![(10, 20)];
        assert!(can_book(&existing, 5, 10));
    }

    #[test]
    fn rejects_invalid_interval() {
        let existing = vec![(10, 20)];
        assert!(!can_book(&existing, 8, 8));
    }

    #[test]
    fn rejects_overlap_any_existing_booking() {
        let existing = vec![(10, 20), (30, 40)];
        assert!(!can_book(&existing, 35, 38));
    }
}

