    Resolve,
    Close,
    Reopen,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Open, Event::Start) => Status::InProgress,
        (Status::Open, Event::Resolve) => Status::Resolved,
        (Status::InProgress, Event::Resolve) => Status::Resolved,
        (Status::Resolved, Event::Close) => Status::Closed,
        (Status::Closed, Event::Reopen) => Status::Open,
        (Status::Resolved, Event::Reopen) => Status::Open,
        _ => status,
    }
}

pub fn apply_events(mut status: Status, events: &[Event]) -> Status {
    for &event in events {
        status = apply_event(status, event);
    }
    status
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn resolved_reopen_goes_back_to_in_progress() {
        assert_eq!(apply_event(Status::Resolved, Event::Reopen), Status::InProgress);
    }

    #[test]
    fn closed_reopen_goes_back_to_open() {
        assert_eq!(apply_event(Status::Closed, Event::Reopen), Status::Open);
    }

    #[test]
    fn close_requires_resolution_first() {
        assert_eq!(apply_event(Status::InProgress, Event::Close), Status::InProgress);
        assert_eq!(apply_event(Status::Open, Event::Close), Status::Open);
    }

    #[test]
    fn sequence_preserves_work_after_reopen() {
        let events = [Event::Start, Event::Resolve, Event::Reopen, Event::Resolve, Event::Close];
        assert_eq!(apply_events(Status::Open, &events), Status::Closed);
    }

    #[test]
    fn reopening_then_closing_without_re_resolving_does_not_close() {
        let events = [Event::Start, Event::Resolve, Event::Reopen, Event::Close];
        assert_eq!(apply_events(Status::Open, &events), Status::InProgress);
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub host: String,
    pub port: u16,
    pub use_tls: bool,
    pub timeout_ms: u32,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
    pub timeout_ms: Option<u32>,
}

pub fn merge_config(
    defaults: &Config,
    file: Option<&PartialConfig>,
    env: Option<&PartialConfig>,
    cli: Option<&PartialConfig>,
) -> Config {
    let mut merged = defaults.clone();

    if let Some(layer) = file {
        apply_layer(&mut merged, layer);
    }
    if let Some(layer) = env {
        apply_layer(&mut merged, layer);
    }
    if let Some(layer) = cli {
        apply_layer(&mut merged, layer);
    }

    merged
}

fn apply_layer(dst: &mut Config, src: &PartialConfig) {
    if let Some(host) = &src.host {
        dst.host = host.clone();
    }
    if let Some(port) = src.port {
        dst.port = port;
    }
    if src.use_tls.unwrap_or(false) {
        dst.use_tls = true;
    }
    if let Some(timeout_ms) = src.timeout_ms {
        dst.timeout_ms = timeout_ms;
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn defaults() -> Config {
        Config {
            host: "localhost".into(),
            port: 8080,
            use_tls: true,
            timeout_ms: 1000,
        }
    }

    #[test]
    fn later_layers_override_earlier_ones() {
        let file = PartialConfig {
            host: Some("file.internal".into()),
            port: Some(7000),
            use_tls: None,
            timeout_ms: Some(1500),
        };
        let env = PartialConfig {
            host: None,
            port: Some(8000),
            use_tls: Some(false),
            timeout_ms: None,
        };
        let cli = PartialConfig {
            host: Some("cli.example.com".into()),
            port: None,
            use_tls: None,
            timeout_ms: Some(2500),
        };

        let merged = merge_config(&defaults(), Some(&file), Some(&env), Some(&cli));

        assert_eq!(merged.host, "cli.example.com");
        assert_eq!(merged.port, 8000);
        assert!(!merged.use_tls);
        assert_eq!(merged.timeout_ms, 2500);
    }

    #[test]
    fn explicit_false_in_higher_precedence_layer_is_preserved() {
        let file = PartialConfig {
            host: None,
            port: None,
            use_tls: Some(true),
            timeout_ms: None,
        };
        let env = PartialConfig {
            host: None,
            port: None,
            use_tls: Some(false),
            timeout_ms: None,
        };

        let merged = merge_config(&defaults(), Some(&file), Some(&env), None);
        assert!(!merged.use_tls);
    }

    #[test]
    fn missing_values_do_not_replace_existing_settings() {
        let file = PartialConfig {
            host: None,
            port: Some(9000),
            use_tls: None,
            timeout_ms: None,
        };
        let cli = PartialConfig::default();

        let merged = merge_config(&defaults(), Some(&file), None, Some(&cli));

        assert_eq!(merged.host, "localhost");
        assert_eq!(merged.port, 9000);
        assert!(merged.use_tls);
        assert_eq!(merged.timeout_ms, 1000);
    }
}

