#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player<'a> {
    pub name: &'a str,
    pub wins: u32,
    pub losses: u32,
}

pub fn leaderboard(players: &[Player<'_>]) -> Vec<String> {
    let mut rows = players.to_vec();
    rows.sort_by(|a, b| {
        b.wins
            .cmp(&a.wins)
            .then_with(|| a.losses.cmp(&b.losses))
    });

    rows.into_iter()
        .map(|p| format!("{}:{}-{}", p.name, p.wins, p.losses))
        .collect()
}

#[cfg(test)]
mod tests {
    use super::{leaderboard, Player};

    #[test]
    fn sorts_by_wins_then_fewer_losses_then_name() {
        let players = vec![
            Player { name: "zoe", wins: 5, losses: 2 },
            Player { name: "amy", wins: 5, losses: 2 },
            Player { name: "max", wins: 6, losses: 4 },
            Player { name: "bob", wins: 5, losses: 1 },
        ];

        assert_eq!(
            leaderboard(&players),
            vec!["max:6-4", "bob:5-1", "amy:5-2", "zoe:5-2"]
        );
    }

    #[test]
    fn duplicate_records_are_kept_and_ordered() {
        let players = vec![
            Player { name: "ivy", wins: 3, losses: 0 },
