#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Order {
    pub month: &'static str,
    pub region: &'static str,
    pub amount_cents: i64,
    pub refunded: bool,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RegionSummary {
    pub region: String,
    pub order_count: usize,
    pub net_cents: i64,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct MonthlyReport {
    pub month: String,
    pub total_orders: usize,
    pub total_net_cents: i64,
    pub regions: Vec<RegionSummary>,
}

pub fn build_monthly_report(orders: &[Order], month: &str) -> MonthlyReport {
    let mut filtered: Vec<&Order> = orders.iter().filter(|o| o.month == month).collect();
    filtered.sort_by(|a, b| a.region.cmp(b.region));

    let mut regions: Vec<RegionSummary> = Vec::new();
    let mut current_region: Option<&str> = None;
    let mut order_count = 0usize;
    let mut net_cents = 0i64;

    for order in filtered {
        if current_region != Some(order.region) {
            if let Some(region) = current_region {
                regions.push(RegionSummary {
                    region: region.to_string(),
                    order_count,
                    net_cents,
                });
            }
            current_region = Some(order.region);
            order_count = 0;
            net_cents = 0;
        }

        if !order.refunded {
            order_count += 1;
            net_cents += order.amount_cents;
        }
    }

    MonthlyReport {
        month: month.to_string(),
        total_orders: regions.iter().map(|r| r.order_count).sum(),
        total_net_cents: regions.iter().map(|r| r.net_cents).sum(),
        regions,
    }
}

