#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    New,
    Active,
    Blocked,
    Done,
    Archived,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Complete,
    Archive,
    Reopen,
    Retry,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::New;
    for event in events {
        status = match (status, *event) {
            (Status::New, Event::Start) => Status::Active,
            (Status::New, Event::Archive) => Status::Archived,
            (Status::Active, Event::Block) => Status::Blocked,
            (Status::Active, Event::Complete) => Status::Done,
            (Status::Active, Event::Archive) => Status::Archived,
            (Status::Blocked, Event::Unblock) => Status::Active,
            (Status::Blocked, Event::Complete) => Status::Done,
            (Status::Blocked, Event::Archive) => Status::Archived,
            (Status::Done, Event::Reopen) => Status::Active,
            (Status::Done, Event::Archive) => Status::Archived,
            (Status::Archived, Event::Reopen) => Status::Active,
            (s, Event::Retry) => s,
            (s, _) => s,
        };
    }
    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event::*, Status};

    #[test]
    fn retry_from_blocked_keeps_it_blocked() {
        let events = [Start, Block, Retry];
        assert_eq!(apply_events(&events), Status::Blocked);
    }

    #[test]
    fn retry_after_done_reopens_work() {
        let events = [Start, Complete, Retry];
        assert_eq!(apply_events(&events), Status::Active);
    }

    #[test]
    fn archived_is_terminal_even_if_reopen_or_retry_arrive() {
        let events = [Start, Complete, Archive, Reopen, Retry, Start, Complete];
        assert_eq!(apply_events(&events), Status::Archived);
    }

    #[test]
    fn only_done_can_reopen() {
        let events = [Archive, Reopen, Start, Complete];
        assert_eq!(apply_events(&events), Status::Archived);
    }

    #[test]
    fn retry_on_new_is_ignored_but_later_start_works() {
        let events = [Retry, Start];
        assert_eq!(apply_events(&events), Status::Active);
    }
}

use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub region: &'static str,
    pub reps: u32,
    pub units: u32,
    pub returned: u32,
}

pub fn region_summary(rows: &[Sale]) -> String {
    let mut totals: BTreeMap<&str, (u32, u32, u32)> = BTreeMap::new();

    for row in rows {
        let entry = totals.entry(row.region).or_insert((0, 0, 0));
        entry.0 += row.reps;
        entry.1 += row.units;
        entry.2 += row.returned;
    }

    let mut lines = Vec::new();
    for (region, (reps, units, returned)) in totals {
        let net = units;
        lines.push(format!("{}|reps={}|net={}|returns={}", region, reps, net, returned));
    }

    lines.join("\n")
}

#[cfg(test)]
mod tests {
    use super::{region_summary, Sale};

    #[test]
    fn groups_regions_and_uses_net_units() {
        let rows = [
            Sale { region: "East", reps: 2, units: 12, returned: 1 },
            Sale { region: "West", reps: 1, units: 7, returned: 0 },
            Sale { region: "East", reps: 3, units: 4, returned: 2 },
        ];

        let out = region_summary(&rows);
        assert_eq!(out, "East|reps=5|net=13|returns=3\nWest|reps=1|net=7|returns=0");
    }

    #[test]
    fn suppresses_zero_return_field_when_region_has_no_returns() {
        let rows = [
            Sale { region: "North", reps: 2, units: 5, returned: 0 },
            Sale { region: "South", reps: 1, units: 9, returned: 1 },
            Sale { region: "North", reps: 1, units: 3, returned: 0 },
        ];

        let out = region_summary(&rows);
        assert_eq!(out, "North|reps=3|net=8\nSouth|reps=1|net=8|returns=1");
    }
}

steps.replace:
if returned == 0 {
    lines.push(format!("{}|reps={}|net={}", region, reps, net));
} else {
    lines.push(format!("{}|reps={}|net={}|returns={}", region, reps, net, returned));
}

