    fn invalid_events_do_not_change_state() {
        let events = [Event::Close, Event::Resolve, Event::Start];
        assert_eq!(apply_events(&events), Status::InProgress);
    }
}

pub fn collect_valid_scores(rows: &[&str]) -> Vec<String> {
    rows.iter()
        .filter_map(|row| {
            let (name, score_text) = row.split_once(':')?;
            let score: i32 = score_text.parse().ok()?;
            if name.is_empty() || score < 0 {
                return None;
            }
            Some(format!("{}={}", name, score))
        })
        .collect()
}

