use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SaleRecord {
    pub region: String,
    pub rep: String,
    pub amount_cents: i64,
    pub refunded: bool,
}

fn parse_record(line: &str) -> Option<SaleRecord> {
    let mut parts = line.split('|');
    let region = parts.next()?.trim();
    let rep = parts.next()?.trim();
    let amount = parts.next()?.trim();
    let refunded = parts.next()?.trim();
    if parts.next().is_some() || region.is_empty() || rep.is_empty() {
        return None;
    }
    let amount_cents = amount.parse::<i64>().ok()?;
    let refunded = match refunded {
        "ok" => false,
        "refund" => true,
        _ => return None,
    };
    Some(SaleRecord {
        region: region.to_string(),
        rep: rep.to_string(),
        amount_cents,
        refunded,
    })
}

pub fn build_region_report(input: &str) -> String {
    let mut totals: BTreeMap<String, i64> = BTreeMap::new();
    let mut valid_rows = 0usize;
    let mut refunded_rows = 0usize;
    let mut invalid_rows = 0usize;

    for line in input.lines().filter(|l| !l.trim().is_empty()) {
        match parse_record(line) {
            Some(rec) => {
                valid_rows += 1;
                if rec.refunded {
                    refunded_rows += 1;
                    *totals.entry(rec.region).or_insert(0) += rec.amount_cents;
                } else {
                    *totals.entry(rec.region).or_insert(0) += rec.amount_cents;
                }
            }
            None => invalid_rows += 1,
        }
    }

    let mut lines = Vec::new();
    for (region, total) in totals {
        lines.push(format!("{}:{}", region, total));
    }
    lines.push(format!(
        "summary:valid={},refunded={},invalid={},regions={}",
        valid_rows,
        refunded_rows,
        invalid_rows,
        lines.len()
    ));
    lines.join("\n")
}

