#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub host: String,
    pub port: u16,
    pub use_tls: bool,
    pub timeout_ms: u64,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
    pub timeout_ms: Option<u64>,
}

pub fn merge_config(base: &Config, env: &PartialConfig, cli: &PartialConfig) -> Config {
    Config {
        host: cli
            .host
            .clone()
            .or_else(|| env.host.clone())
            .unwrap_or_else(|| base.host.clone()),
        port: cli.port.or(env.port).unwrap_or(base.port),
        use_tls: cli.use_tls.unwrap_or(env.use_tls.unwrap_or(base.use_tls)),
        timeout_ms: env.timeout_ms.or(cli.timeout_ms).unwrap_or(base.timeout_ms),
    }
}

