        Config {
            host: "localhost".into(),
            port: 8080,
            use_tls: true,
            timeout_ms: 1000,
        }
    }

    #[test]
    fn cli_overrides_env_and_base_for_scalar_values() {
        let env = PartialConfig {
            host: Some("env.internal".into()),
            port: Some(9000),
            use_tls: Some(true),
            timeout_ms: Some(2000),
        };
        let cli = PartialConfig {
            host: Some("cli.internal".into()),
            port: Some(7000),
            use_tls: None,
            timeout_ms: Some(3000),
        };

        let merged = merge_config(&base(), &env, &cli);
        assert_eq!(
            merged,
            Config {
                host: "cli.internal".into(),
                port: 7000,
                use_tls: true,
                timeout_ms: 3000,
            }
        );
    }

    #[test]
    fn env_fills_missing_values_when_cli_absent() {
        let env = PartialConfig {
            host: None,
            port: Some(9090),
            use_tls: Some(false),
            timeout_ms: Some(2500),
        };
        let cli = PartialConfig::default();

        let merged = merge_config(&base(), &env, &cli);
        assert_eq!(merged.host, "localhost");
        assert_eq!(merged.port, 9090);
        assert!(!merged.use_tls);
        assert_eq!(merged.timeout_ms, 2500);
    }

