struct Booking {
    room: &'static str,
    start: u32,
    end: u32,
}

fn fmt_time(minutes: u32) -> String {
    format!("{:02}:{:02}", minutes / 60, minutes % 60)
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn conflict_lines(bookings: &[Booking], room: &str) -> Vec<String> {
    let mut lines = Vec::new();
    for i in 0..bookings.len() {
        for j in i + 1..bookings.len() {
            let a = &bookings[i];
            let b = &bookings[j];
            if a.room == room && b.room == room && overlaps(a, b) {
                lines.push(format!(
                    "{}-{} overlaps {}-{}",
                    fmt_time(a.start),
                    fmt_time(a.end),
                    fmt_time(b.start),
                    fmt_time(b.end)
                ));
            }
        }
    }
    lines
}

fn main() {
    let bookings = vec![
        Booking { room: "A", start: 9 * 60, end: 10 * 60 },
        Booking { room: "A", start: 9 * 60 + 30, end: 11 * 60 },
        Booking { room: "A", start: 11 * 60, end: 12 * 60 },
        Booking { room: "A", start: 12 * 60, end: 13 * 60 },
        Booking { room: "A", start: 11 * 60, end: 11 * 60 + 30 },
        Booking { room: "B", start: 13 * 60, end: 14 * 60 },
        Booking { room: "B", start: 13 * 60 + 30, end: 15 * 60 },
    ];

    let mut out = String::new();
    out.push_str("Room A conflicts:\n");
    out.push_str(&conflict_lines(&bookings, "A").join("\n"));
    out.push_str("\nRoom B conflicts:\n");
    out.push_str(&conflict_lines(&bookings, "B").join("\n"));
    println!("{}", out);
}

