fn apply_event(state: &str, event: &str) -> String {
    match event {
        "create" => "open".to_string(),
        "start" => {
            if state == "open" {
                "in_progress".to_string()
            } else {
                state.to_string()
            }
        }
        "resolve" => {
            if state == "in_progress" {
                "resolved".to_string()
            } else {
                state.to_string()
            }
        }
        "close" => {
            if state == "resolved" {
                "closed".to_string()
            } else {
                state.to_string()
            }
        }
        "reopen" => "open".to_string(),
        _ => state.to_string(),
    }
}

fn main() {
    let tickets = vec![
        ("A", vec!["create", "start", "resolve", "close"]),
        ("B", vec!["create", "start", "resolve", "close", "reopen"]),
        ("C", vec!["create", "resolve"]),
    ];

    let mut lines = Vec::new();
    for (id, events) in tickets {
        let mut state = "new".to_string();
        for event in events {
