struct Booking {
    id: &'static str,
    start: u32,
    end: u32,
}

fn overlaps(a: Booking, b: Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn accept(bookings: &[Booking]) -> Vec<&'static str> {
    let mut accepted: Vec<Booking> = Vec::new();
    let mut ids = Vec::new();

    for &b in bookings {
        if accepted.iter().all(|&a| !overlaps(a, b)) {
            accepted.push(b);
            ids.push(b.id);
        }
    }

    ids
}

fn main() {
    let bookings = [
        Booking { id: "A", start: 1, end: 3 },
        Booking { id: "B", start: 3, end: 5 },
        Booking { id: "C", start: 5, end: 7 },
        Booking { id: "D", start: 6, end: 8 },
        Booking { id: "E", start: 8, end: 10 },
    ];

    let ids = accept(&bookings);
    println!("accepted: {}", ids.join(","));
}

