enum Event {
    Completed { retries: u8, warnings: u8 },
    TimedOut { partial: bool },
    Rejected { code: u16 },
    Cancelled,
}

fn classify(event: &Event) -> &'static str {
    match event {
        Event::Completed { retries, warnings } => {
            if *retries > 0 || *warnings > 0 {
                "warn"
            } else {
                "ok"
            }
        }
        Event::TimedOut { partial } => {
            if *partial {
                "skip"
            } else {
                "fail"
            }
        }
        Event::Rejected { code } => {
            if *code >= 500 {
                "skip"
            } else {
                "fail"
            }
        }
        Event::Cancelled => "fail",
    }
}

fn main() {
    let jobs = [
        ("alice", Event::Completed { retries: 0, warnings: 0 }),
        ("bob", Event::Completed { retries: 1, warnings: 0 }),
        ("cora", Event::Rejected { code: 503 }),
