use std::collections::BTreeMap;

fn parse_pairs(input: &str) -> BTreeMap<String, String> {
    let mut out = BTreeMap::new();
    for part in input.split(';') {
        let part = part.trim();
        if part.is_empty() {
            continue;
        }
        if let Some((k, v)) = part.split_once('=') {
            out.insert(k.trim().to_string(), v.trim().to_string());
        }
    }
    out
}

fn merge_config(
    defaults: &BTreeMap<String, String>,
    file_cfg: &BTreeMap<String, String>,
    env_cfg: &BTreeMap<String, String>,
    cli_cfg: &BTreeMap<String, String>,
) -> BTreeMap<String, String> {
    let mut merged = BTreeMap::new();

    for (k, v) in defaults {
        merged.insert(k.clone(), v.clone());
    }
    for (k, v) in env_cfg {
        merged.insert(k.clone(), v.clone());
    }
    for (k, v) in file_cfg {
        merged.insert(k.clone(), v.clone());
    }
    for (k, v) in cli_cfg {
        merged.insert(k.clone(), v.clone());
    }

    merged
}

fn main() {
    let defaults = parse_pairs("host=localhost;port=8080;tls=false;mode=prod");
    let file_cfg = parse_pairs("host=file.local;port=8000;mode=dev");
    let env_cfg = parse_pairs("host=env.local;tls=true");
    let cli_cfg = parse_pairs("port=9090");

    let merged = merge_config(&defaults, &file_cfg, &env_cfg, &cli_cfg);
    let order = ["host", "port", "tls", "mode"];

    for key in order {
        if let Some(value) = merged.get(key) {
            println!("{}={}", key, value);
        }
    }
}

