fn parse_line(line: &str) -> Option<(u32, &'static str, u32)> {
    let mut id = None;
    let mut level = None;
    let mut code = None;

    for part in line.split(';') {
        let (key, value) = part.split_once('=')?;
        match key {
            "id" => id = value.parse::<u32>().ok(),
            "level" => {
                if matches!(value, "INFO" | "WARN" | "ERROR") {
                    level = Some(Box::leak(value.to_string().into_boxed_str()));
                }
            }
            "code" => code = value.parse::<u32>().ok(),
            _ => {}
        }
    }

    Some((id?, level?, code?))
}

fn is_valid(id: u32, level: &str, code: u32) -> bool {
    if id == 0 {
        return false;
    }
    match level {
        "INFO" => code < 200,
        "WARN" => code < 500,
        "ERROR" => code >= 500,
        _ => false,
    }
}

fn main() {
    let input = [
        "id=101;level=INFO;code=120",
        "id=102;level=WARN;code=500",
        "level=ERROR;id=103;code=503",
        "id=0;level=INFO;code=100",
        "id=104;level=DEBUG;code=100",
        "id=105;level=ERROR;code=550;note=urgent",
    ];

    let mut valid = 0;
    let mut invalid = 0;
    let mut accepted_ids = Vec::new();

    for line in input {
        match parse_line(line) {
            Some((id, level, code)) if is_valid(id, level, code) => {
                valid += 1;
                accepted_ids.push(id.to_string());
            }
            _ => invalid += 1,
        }
    }

    println!("valid: {}", valid);
    println!("invalid: {}", invalid);
    println!("accepted_ids: {}", accepted_ids.join(","));
}

