enum Event {
    Restock(u32),
    Sale(u32),
    Refund(u32),
    Audit,
    Stop,
}

struct Shop {
    apples: u32,
    closed: bool,
}

fn apply(shop: &mut Shop, event: Event) -> String {
    match event {
        Event::Restock(n) => {
            shop.apples += n;
            format!("restock {} -> +{} apples", n, n)
        }
        Event::Sale(n) => {
            if shop.apples >= n {
                shop.apples -= n;
                format!("sale {} -> sold {} apples", n, n)
            } else {
                shop.apples = 0;
                format!("sale {} -> only {} apples available", n, n)
            }
        }
        Event::Refund(n) => format!("refund {} -> ignored", n),
        Event::Audit => format!("audit -> apples:{}", shop.apples),
        Event::Stop => {
            format!("stop -> done")
        }
    }
}

