struct PartialConfig {
    host: Option<String>,
    port: Option<u16>,
    mode: Option<String>,
    verbose: Option<bool>,
}

fn merge(defaults: &Config, profile: &PartialConfig, cli: &PartialConfig) -> Config {
    let host = cli
        .host
        .clone()
        .or_else(|| profile.host.clone())
        .unwrap_or_else(|| defaults.host.clone());

