        .or_else(|| cli.mode.clone())
        .unwrap_or_else(|| defaults.mode.clone());

    let verbose = cli.verbose.or(profile.verbose).unwrap_or(defaults.verbose);

    Config {
        host,
        port,
        mode,
        verbose,
    }
}

