struct Booking {
    id: &'static str,
    start: u32,
    end: u32,
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn main() {
    let requests = [
        Booking { id: "A", start: 9, end: 11 },
        Booking { id: "B", start: 10, end: 12 },
        Booking { id: "C", start: 11, end: 13 },
        Booking { id: "D", start: 8, end: 9 },
        Booking { id: "E", start: 13, end: 15 },
        Booking { id: "F", start: 15, end: 16 },
    ];

    let mut accepted: Vec<&Booking> = Vec::new();
    let mut accepted_ids: Vec<&str> = Vec::new();
    let mut rejected = 0;

    for req in &requests {
        let conflict = accepted.iter().any(|booked| overlaps(booked, req));
        if conflict {
            rejected += 1;
        } else {
            accepted.push(req);
            accepted_ids.push(req.id);
        }
    }

    println!("accepted: {}", accepted.len());
    println!("rejected: {}", rejected);
    println!("accepted_ids: {}", accepted_ids.join(", "));
}

