fn summarize(input: &str) -> (usize, usize, i32, Vec<String>) {
    let mut ok = 0usize;
    let mut bad = 0usize;
    let mut total_qty = 0i32;
    let mut ids = Vec::new();
    let mut seen = HashSet::new();

    for line in input.lines().skip(1) {
        if line.is_empty() {
            continue;
        }
        let parts: Vec<&str> = line.split(',').collect();
        if parts.len() != 3 {
            bad += 1;
            continue;
