        let id = parts[0];
        let name = parts[1];
        let qty = parts[2].parse::<i32>().unwrap_or(0);

        if id.is_empty() || name.is_empty() {
            bad += 1;
            continue;
        }

        if qty < 0 {
            total_qty += qty;
        }

        if seen.insert(id.to_string()) {
            ok += 1;
            total_qty += qty;
            ids.push(id.to_string());
        }
    }

    (ok, bad, total_qty, ids)
}

