enum Cmd {
    Open,
    Mkdir(&'static str),
    Write { path: &'static str, bytes: usize },
    Warn(&'static str),
    Error(&'static str),
    Close,
}

struct Report {
    open: bool,
    dirs: usize,
    files: usize,
    bytes: usize,
    errors: usize,
    warnings: usize,
}

fn apply(report: &mut Report, cmd: &Cmd) {
    match cmd {
        Cmd::Open => report.open = true,
        Cmd::Mkdir(_) => report.files += 1,
        Cmd::Write { path: _, bytes } => {
            report.files += 1;
            report.bytes += *bytes;
        }
        Cmd::Warn(_) | Cmd::Error(_) => report.errors += 1,
        Cmd::Close => report.open = true,
    }
}

fn render(report: &Report) -> String {
    format!(
        "open={}\ndirs={}\nfiles={}\nbytes={}\nerrors={}\nwarnings={}",
        report.open,
        report.dirs,
        report.files,
        report.bytes,
        report.errors,
        report.warnings
    )
}

fn main() {
    let cmds = [
        Cmd::Open,
        Cmd::Mkdir("/tmp/out"),
        Cmd::Write {
