        Cmd::Mkdir("/tmp/out/archive"),
        Cmd::Write {
            path: "/tmp/out/archive/b.log",
            bytes: 64,
        },
        Cmd::Error("disk slow"),
        Cmd::Write {
            path: "/tmp/out/c.log",
            bytes: 3,
        },
        Cmd::Warn("retry used"),
