fn parse_hhmm(s: &str) -> i32 {
    let (h, m) = s.split_once(':').unwrap();
    h.parse::<i32>().unwrap() * 60 + m.parse::<i32>().unwrap()
}

fn overlaps(a: (i32, i32), b: (i32, i32)) -> bool {
    !(a.1 < b.0 || b.1 < a.0)
}

fn can_book(existing: &[(i32, i32)], req: (i32, i32)) -> bool {
    existing.iter().all(|&slot| !overlaps(slot, req))
}

fn main() {
    let requests = [
        ("09:00", "10:00"),
        ("10:00", "11:00"),
        ("09:30", "09:45"),
        ("11:00", "11:30"),
        ("10:30", "11:15"),
        ("09:00", "10:00"),
    ];

    let mut booked: Vec<(i32, i32)> = Vec::new();
    let mut out = Vec::new();

    for (start_s, end_s) in requests {
        let req = (parse_hhmm(start_s), parse_hhmm(end_s));
        if can_book(&booked, req) {
            booked.push(req);
            out.push(format!("ACCEPT {}-{}", start_s, end_s));
        } else {
            out.push(format!("REJECT {}-{}", start_s, end_s));
        }
    }

    println!("{}", out.join("\n"));
}

