fn parse_line(line: &str) -> Result<Record, String> {
    let parts: Vec<&str> = line.split('|').collect();
    if parts.len() < 4 {
        return Err("wrong field count".to_string());
    }

    let id = parts[0].parse::<u32>().map_err(|_| "invalid id".to_string())?;
    let name = parts[1].to_string();
    let score = parts[2].parse::<u8>().map_err(|_| "invalid score".to_string())?;
    let active = match parts[3] {
        "true" => true,
        "false" => false,
        _ => false,
    };

    Ok(Record { id, name, score, active })
}

