                out.push(format!("OK {} {}", rec.id, rec.name));
            }
            Err(msg) => {
                let id = line.split('|').next().unwrap_or("?");
                out.push(format!("ERR {} {}", id, msg));
            }
        }
    }

    println!("{}", out.join("\n"));
}

