#[derive(Clone, Debug)]
struct Config {
    mode: Option<&'static str>,
    retries: Option<u32>,
    timeout: Option<u32>,
    verbose: Option<bool>,
    features: Vec<&'static str>,
}

fn merge(base: &Config, env: &Config, cli: &Config) -> Config {
    Config {
        mode: base.mode.or(env.mode).or(cli.mode),
        retries: base.retries.or(env.retries).or(cli.retries),
        timeout: base.timeout.or(env.timeout).or(cli.timeout),
        verbose: cli.verbose.or(env.verbose).or(base.verbose),
        features: {
            let mut merged = base.features.clone();
            merged.extend(env.features.iter().copied());
            merged
        },
    }
}

fn render(cfg: &Config) -> String {
    let mut out = String::new();
    writeln!(&mut out, "mode={}", cfg.mode.unwrap_or("standard")).unwrap();
    writeln!(&mut out, "retries={}", cfg.retries.unwrap_or(3)).unwrap();
    writeln!(&mut out, "timeout={}", cfg.timeout.unwrap_or(30)).unwrap();
    writeln!(&mut out, "verbose={}", cfg.verbose.unwrap_or(false)).unwrap();
    write!(&mut out, "features={}", cfg.features.join(",")).unwrap();
    out
}

fn main() {
    let defaults = Config {
