        Order { month: "2024-02", region: "north", amount: 50, refunded: false },
        Order { month: "2024-02", region: "north", amount: 70, refunded: true },
        Order { month: "2024-02", region: "north", amount: 100, refunded: false },
    ]
}

fn render_report(orders: &[Order]) -> String {
    let mut monthly: BTreeMap<&str, BTreeMap<&str, (u32, u32)>> = BTreeMap::new();

    for order in orders {
        let region_totals = monthly.entry(order.month).or_default();
        let entry = region_totals.entry(order.region).or_insert((0, 0));
        entry.0 += 1;
        entry.1 += order.amount;
    }

    let mut out = String::new();
    let mut grand_orders = 0;
    let mut grand_revenue = 0;

    for (month, regions) in monthly {
        out.push_str(month);
        out.push('\n');
        for (region, (orders, revenue)) in regions {
            out.push_str(&format!("  {}: orders={} revenue={}\n", region, orders, revenue));
            grand_orders += orders;
            grand_revenue += revenue;
        }
    }

    out.push_str(&format!("grand_total: orders={} revenue={}", grand_orders, grand_revenue));
    out
}

