    id: &'static str,
    room: &'static str,
    start: u32,
    end: u32,
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn conflict<'a>(existing: &'a [Booking], req: &Booking) -> Option<&'a Booking> {
    existing.iter().find(|b| overlaps(b, req))
}

fn main() {
    let requests = [
        Booking { id: "A", room: "red", start: 540, end: 600 },
        Booking { id: "B", room: "red", start: 600, end: 630 },
        Booking { id: "C", room: "red", start: 570, end: 585 },
        Booking { id: "D", room: "blue", start: 570, end: 585 },
        Booking { id: "E", room: "red", start: 620, end: 660 },
        Booking { id: "F", room: "red", start: 630, end: 660 },
        Booking { id: "G", room: "red", start: 640, end: 650 },
        Booking { id: "H", room: "red", start: 660, end: 690 },
    ];

    let mut accepted: Vec<Booking> = Vec::new();
    let mut lines: Vec<String> = Vec::new();

    for req in requests {
        if let Some(hit) = conflict(&accepted, &req) {
            lines.push(format!(
                "rejected: {} conflicts_with={} room={} [{},{})",
                req.id, hit.id, req.room, req.start, req.end
            ));
        } else {
            accepted.push(req);
            lines.push(format!(
                "accepted: {} room={} [{},{})",
                req.id, req.room, req.start, req.end
            ));
        }
    }

    print!("{}", lines.join("\n"));
}

