use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    Todo,
    InProgress,
    Closed,
}

impl Status {
    fn as_str(self) -> &'static str {
        match self {
            Status::Todo => "todo",
            Status::InProgress => "in_progress",
            Status::Closed => "closed",
        }
    }
}

fn apply_event(state: Option<Status>, event: &str) -> Option<Status> {
    match (state, event) {
        (None, "create") => Some(Status::Todo),
        (Some(Status::Todo), "start") => Some(Status::InProgress),
        (_, "close") => Some(Status::Closed),
        (Some(Status::Closed), "reopen") => Some(Status::Todo),
        (s, _) => s,
    }
}

fn main() {
    let events = [
        ("A", "create"),
        ("A", "start"),
        ("A", "close"),
        ("A", "reopen"),
        ("A", "close"),
        ("B", "create"),
        ("B", "close"),
        ("C", "create"),
        ("C", "start"),
        ("C", "reopen"),
    ];

    let mut states: BTreeMap<&str, Option<Status>> = BTreeMap::new();
    for (id, event) in events {
        let current = states.get(id).copied().flatten();
        let next = apply_event(current, event);
        states.insert(id, next);
    }

    for (id, state) in states {
        if let Some(status) = state {
            println!("{}: {}", id, status.as_str());
        }
    }
}

use std::collections::BTreeMap;

#[derive(Clone, Copy, PartialEq, Eq)]
enum State {
    Open,
    InProgress,
    Blocked,
    Closed,
}

enum Event {
    New(&'static str),
    Start(&'static str),
    Block(&'static str),
    Resume(&'static str),
    Close(&'static str),
    Reopen(&'static str),
}

fn main() {
    let events = [
        Event::New("A"),
        Event::Start("A"),
        Event::Close("A"),
        Event::Reopen("A"),
        Event::Block("A"),
        Event::Resume("A"),
        Event::Close("A"),
        Event::New("B"),
        Event::Block("B"),
        Event::Resume("B"),
        Event::Start("B"),
        Event::New("C"),
        Event::Close("C"),
        Event::Reopen("D"),
        Event::New("D"),
        Event::Close("D"),
        Event::Close("D"),
    ];

    let mut tickets: BTreeMap<&'static str, State> = BTreeMap::new();
    let mut invalid_reopens = 0;
    let mut invalid_closes = 0;

    for event in events {
        match event {
            Event::New(id) => {
                tickets.insert(id, State::Open);
            }
            Event::Start(id) => {
                if let Some(state) = tickets.get_mut(id) {
                    if *state != State::Closed {
                        *state = State::InProgress;
                    }
                }
            }
            Event::Block(id) => {
                if let Some(state) = tickets.get_mut(id) {
                    if *state == State::InProgress || *state == State::Open {
                        *state = State::Blocked;
                    }
                }
            }
            Event::Resume(id) => {
                if let Some(state) = tickets.get_mut(id) {
                    if *state == State::Blocked {
                        *state = State::Open;
                    }
                }
            }
            Event::Close(id) => {
                if let Some(state) = tickets.get_mut(id) {
                    *state = State::Closed;
                } else {
                    invalid_closes += 1;
                }
            }
            Event::Reopen(id) => {
                if let Some(state) = tickets.get_mut(id) {
                    *state = State::Open;
                } else {
                    invalid_reopens += 1;
                }
            }
        }
    }

    let mut open = 0;
    let mut in_progress = 0;
    let mut blocked = 0;
    let mut closed = 0;

    for state in tickets.values() {
        match state {
            State::Open => open += 1,
            State::InProgress => in_progress += 1,
            State::Blocked => blocked += 1,
            State::Closed => closed += 1,
        }
    }

    println!("open: {}", open);
    println!("in_progress: {}", in_progress);
    println!("blocked: {}", blocked);
    println!("closed: {}", closed);
    println!("invalid_reopens: {}", invalid_reopens);
    println!("invalid_closes: {}", invalid_closes);
}

