use std::collections::BTreeMap;

#[derive(Clone, Copy)]
struct Booking {
    start: u32,
    end: u32,
}

fn overlaps(a: Booking, b: Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn can_book(schedule: &BTreeMap<&str, Vec<Booking>>, room: &str, request: Booking) -> bool {
    if let Some(existing) = schedule.get(room) {
        for &slot in existing {
            if overlaps(slot, request) {
                return false;
            }
        }
    }
    true
}

fn main() {
    let mut schedule: BTreeMap<&str, Vec<Booking>> = BTreeMap::new();
    schedule.insert(
        "room-a",
        vec![Booking { start: 9, end: 12 }, Booking { start: 14, end: 16 }],
    );
    schedule.insert(
        "room-b",
        vec![Booking { start: 3, end: 5 }, Booking { start: 5, end: 7 }, Booking { start: 8, end: 8 }],
    );

    let requests = [
        ("room-a", Booking { start: 10, end: 12 }),
        ("room-a", Booking { start: 12, end: 14 }),
        ("room-a", Booking { start: 14, end: 14 }),
        ("room-b", Booking { start: 3, end: 5 }),
        ("room-b", Booking { start: 5, end: 7 }),
        ("room-b", Booking { start: 7, end: 8 }),
        ("room-c", Booking { start: 1, end: 2 }),
    ];

    for (room, req) in requests {
        let status = if can_book(&schedule, room, req) { "OK" } else { "CONFLICT" };
        println!("{} {}-{} => {}", room, req.start, req.end, status);
    }
}

