pub fn parse_record(input: &str) -> Result<(String, u16), String> {
    let mut parts = input.splitn(2, ':');
    let name = parts.next().ok_or("missing name")?;
    let qty = parts.next().ok_or("missing quantity")?;

    if name.is_empty() {
        return Err("missing name".into());
    }
    if !name.chars().all(|c| c.is_ascii_lowercase() || c == '_') {
        return Err("invalid name".into());
    }
    if qty.is_empty() {
        return Err("missing quantity".into());
    }
    if qty.len() > 1 && qty.starts_with('0') {
        return Err("leading zero".into());
    }
    let value: u16 = qty.parse().map_err(|_| "invalid quantity")?;
    if value == 0 {
        return Err("quantity must be positive".into());
    }

    Ok((name.to_string(), value))
}

#[cfg(test)]
mod tests {
    use super::parse_record;

    #[test]
    fn parses_valid_record() {
        assert_eq!(parse_record("apple_2:15"), Ok(("apple_2".to_string(), 15)));
    }

    #[test]
    fn rejects_missing_separator() {
        assert_eq!(parse_record("apple_2"), Err("missing quantity".to_string()));
    }

    #[test]
    fn rejects_empty_name() {
        assert_eq!(parse_record(":5"), Err("missing name".to_string()));
    }

    #[test]
    fn rejects_bad_name_chars() {
        assert_eq!(parse_record("Apple:5"), Err("invalid name".to_string()));
        assert_eq!(parse_record("item-1:5"), Err("invalid name".to_string()));
    }

    #[test]
    fn rejects_missing_or_bad_quantity() {
        assert_eq!(parse_record("apple:"), Err("missing quantity".to_string()));
        assert_eq!(parse_record("apple:xyz"), Err("invalid quantity".to_string()));
    }

    #[test]
    fn rejects_zero_and_leading_zero_quantity() {
        assert_eq!(parse_record("apple:0"), Err("quantity must be positive".to_string()));
        assert_eq!(parse_record("apple:07"), Err("leading zero".to_string()));
    }
}

