        ("Hawks", 2, "Moles", 1),
        ("Foxes", 0, "Hawks", 0),
        ("Bears", 2, "Lynx", 1),
    ];

    let mut table: BTreeMap<&str, TeamStat> = BTreeMap::new();

    for (home, hg, away, ag) in matches {
        {
            let home_stat = table.entry(home).or_default();
            home_stat.gf += hg;
            home_stat.ga += ag;
            if hg > ag {
                home_stat.pts += 3;
            } else if hg == ag {
                home_stat.pts += 1;
            }
