        {
            let away_stat = table.entry(away).or_default();
            away_stat.gf += ag;
            away_stat.ga += hg;
            if ag > hg {
                away_stat.pts += 3;
            } else if ag == hg {
                away_stat.pts += 1;
            }
        }
    }

